from cryptography.hazmat.primitives import padding
from cryptography.hazmat.primitives.ciphers import Cipher, algorithms, modes
from cryptography.hazmat.backends import default_backend
import base64
import os

def encrypt_credit_card(credit_card_number):
    key = os.environ['ENCRYPTION_KEY'].encode()
    iv = os.urandom(16)
    cipher = Cipher(algorithms.AES(key), modes.CBC(iv), backend=default_backend())
    encryptor = cipher.encryptor()

    padder = padding.PKCS7(cipher.algorithm.block_size * 8).padder()
    padded_data = padder.update(credit_card_number.encode()) + padder.finalize()

    encrypted_padded_data = encryptor.update(padded_data) + encryptor.finalize()

    return base64.b64encode(iv + encrypted_padded_data)

def decrypt_credit_card(encrypted_credit_card_number):
    key = os.environ['ENCRYPTION_KEY'].encode()
    iv = base64.b64decode(encrypted_credit_card_number)[:16]
    cipher = Cipher(algorithms.AES(key), modes.CBC(iv), backend=default_backend())
    decryptor = cipher.decryptor()

    encrypted_padded_data = base64.b64decode(encrypted_credit_card_number)[16:]
    decrypted_padded_data = decryptor.update(encrypted_padded_data) + decryptor.finalize()
    
    unpadder = padding.PKCS7(cipher.algorithm.block_size * 8).unpadder()
    credit_card_number = unpadder.update(decrypted_padded_data) + unpadder.finalize()

    return credit_card_number.decode()